theorem ded281 (P : ℝ → ℝ → ℝ) :
  let Λ(P) := {m : ℕ × ℕ | P (m.1 : ℝ) (m.2 : ℝ) ≠ 0};
  let D_B (B : Set (ℕ × ℕ)) := {x : ℝ × ℝ | ∀ b ∈ B, |x.1 ^ b.1 * x.2 ^ b.2| ≤ 1};
  let cone (B : Set (ℕ × ℕ)) := {v : ℝ × ℝ | ∃ (alpha : ℕ × ℕ → ℝ), (∀ b ∈ B, alpha b ≥ 0) ∧ v = ∑ b ∈ B, alpha b • (b.1 : ℝ, b.2 : ℝ)};
  let N (P : ℝ → ℝ → ℝ) (D : Set (ℝ × ℝ)) := convexHull (∑ m ∈ Λ(P), (m.1 : ℝ, m.2 : ℝ) + cone D);
  N P (D_B {⟨1, 0⟩, ⟨0, 1⟩}) = convexHull (Λ(P) + cone {⟨1, 0⟩, ⟨0, 1⟩}) ∧
  N P (D_B {⟨-1, 0⟩, ⟨0, -1⟩}) = convexHull (Λ(P) + cone {⟨-1, 0⟩, ⟨0, -1⟩}) ∧
  N P (D_B {⟨0, 0⟩}) = convexHull (Λ(P))

